    75→// redistributeHints redistributes hints based in the provided EndpointSlices.
    76→// It allocates endpoints from the provided givingZones to the provided
    77→// receivingZones. This returns a map that represents the changes in allocated
    78→// endpoints by zone.
    79→func redistributeHints(logger klog.Logger, slices []*discovery.EndpointSlice, givingZones, receivingZones map[string]int) map[string]int {
    80→	redistributions := map[string]int{}
    81→
    82→	for _, slice := range slices {
    83→		for i, endpoint := range slice.Endpoints {
    84→			if !EndpointReady(endpoint) {
    85→				endpoint.Hints = nil
    86→				continue
    87→			}
    88→			if len(givingZones) == 0 || len(receivingZones) == 0 {
    89→				return redistributions
    90→			}
    91→			if endpoint.Zone == nil || *endpoint.Zone == "" {
    92→				// This should always be caught earlier in AddHints()
    93→				logger.Info("Endpoint found without zone specified")
    94→				continue
    95→			}
    96→
    97→			givingZone := *endpoint.Zone
    98→			numToGive, ok := givingZones[givingZone]
    99→			if ok && numToGive > 0 {
   100→				for receivingZone, numToReceive := range receivingZones {
   101→					if numToReceive > 0 {
   102→						slice.Endpoints[i].Hints = &discovery.EndpointHints{ForZones: []discovery.ForZone{{Name: receivingZone}}}
   103→						if numToGive == 1 {
   104→							delete(givingZones, givingZone)
   105→						} else {
   106→							givingZones[givingZone]--
   107→						}
   108→						if numToReceive == 1 {
   109→							delete(receivingZones, receivingZone)
   110→						} else {
   111→							receivingZones[receivingZone]--
   112→						}
   113→
   114→						redistributions[receivingZone]++
   115→						redistributions[givingZone]--
   116→
   117→						break
   118→					}
   119→				}
   120→			}
   121→		}
   122→	}
   123→	return redistributions
   124→}
   125→
   126→// getGivingAndReceivingZones returns the number of endpoints each zone should
   127→// give to other zones along with the number of endpoints each zone should
   128→// receive from other zones. This is calculated with the provided allocations
   129→// (desired state) and allocatedHintsByZone (current state).
   130→func getGivingAndReceivingZones(allocations map[string]allocation, allocatedHintsByZone map[string]int) (map[string]int, map[string]int) {
   131→	// 1. Determine the precise number of additional endpoints each zone has
   132→	//    (giving) or needs (receiving).
   133→	givingZonesDesired := map[string]float64{}
   134→	receivingZonesDesired := map[string]float64{}
   135→
   136→	for zone, allocation := range allocations {
   137→		allocatedHints, _ := allocatedHintsByZone[zone]
   138→		target := allocation.desired
   139→		if float64(allocatedHints) > target {
   140→			givingZonesDesired[zone] = float64(allocatedHints) - target
   141→		} else if float64(allocatedHints) < target {
   142→			receivingZonesDesired[zone] = target - float64(allocatedHints)
   143→		}
   144→	}
   145→
   146→	// 2. Convert the precise numbers needed into ints representing real
   147→	//    endpoints given from one zone to another.
   148→	givingZones := map[string]int{}
   149→	receivingZones := map[string]int{}
   150→
   151→	for {
   152→		givingZone, numToGive := getMost(givingZonesDesired)
   153→		receivingZone, numToReceive := getMost(receivingZonesDesired)
   154→
   155→		// return early if any of the following are true:
   156→		// - giving OR receiving zone are unspecified
   157→		// - giving AND receiving zones have less than 1 endpoint left to give or receive
   158→		// - giving OR receiving zones have less than 0.5 endpoints left to give or receive
   159→		if givingZone == "" || receivingZone == "" || (numToGive < 1.0 && numToReceive < 1.0) || numToGive < 0.5 || numToReceive < 0.5 {
   160→			break
   161→		}
   162→
   163→		givingZones[givingZone]++
   164→		givingZonesDesired[givingZone]--
   165→		receivingZones[receivingZone]++
   166→		receivingZonesDesired[receivingZone]--
   167→	}
   168→
   169→	return givingZones, receivingZones
   170→}
   171→
   172→// getMost accepts a map[string]float64 and returns the string and float64 that
   173→// represent the greatest value in this provided map. This function is not very
   174→// efficient but it is expected that len() will rarely be greater than 2.
   175→func getMost(zones map[string]float64) (string, float64) {
   176→	zone := ""
   177→	num := 0.0
   178→	for z, n := range zones {
   179→		if n > num {
   180→			zone = z
   181→			num = n
   182→		}
   183→	}
   184→
   185→	return zone, num
   186→}
   187→
   188→// getHintsByZone returns the number of hints allocated to each zone by the
   189→// provided EndpointSlice. This function returns nil to indicate that the
   190→// current allocations are invalid and that the EndpointSlice needs to be
   191→// updated. This could be caused by:
   192→// - A hint for a zone that no longer requires any allocations.
   193→// - An endpoint with no hints.
   194→// - Hints that would make minimum allocations impossible.
   195→func getHintsByZone(slice *discovery.EndpointSlice, allocatedHintsByZone EndpointZoneInfo, allocations map[string]allocation) map[string]int {
   196→	hintsByZone := map[string]int{}
   197→	for _, endpoint := range slice.Endpoints {
   198→		if !EndpointReady(endpoint) {
   199→			continue
   200→		}
   201→		if endpoint.Hints == nil || len(endpoint.Hints.ForZones) == 0 {
   202→			return nil
   203→		}
   204→
   205→		for i := range endpoint.Hints.ForZones {
   206→			zone := endpoint.Hints.ForZones[i].Name
   207→			if _, ok := allocations[zone]; !ok {
   208→				return nil
   209→			}
   210→			hintsByZone[zone]++
   211→		}
   212→	}
   213→
   214→	for zone, numHints := range hintsByZone {
   215→		alreadyAllocated, _ := allocatedHintsByZone[zone]
   216→		allocation, ok := allocations[zone]
   217→		if !ok || (numHints+alreadyAllocated) > allocation.maximum {
   218→			return nil
   219→		}
   220→	}
   221→
   222→	return hintsByZone
   223→}
